('Navos Behavioral Health Hospital', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', '70-bed inpatient psychiatric hospital providing crisis stabilization and treatment for adults experiencing acute mental health crises. 24-hour crisis line: 1-866-427-4747. Part of MultiCare health system.', '2600 SW Holden Street', 'Seattle', 'King', 'WA', '98126', '(206) 933-7000', 'https://www.navos.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{70-bed inpatient psychiatric hospital providing crisis stabilization and treatment for adults experiencing acute mental health crises,24-hour crisis line: 1-866-427-4747,Part of MultiCare health system}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Navos Mental Health & Wellness Center (Outpatient, Burien)', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Outpatient mental health services for adults, youth, and children, including assessment, therapy, medication management, and chemical dependency treatment. Serves those vulnerable to mental illness, addiction, trauma, and abuse. Accepts Medicaid.', '1210 SW 136th Street', 'Burien', 'King', 'WA', '98166', '(206) 248-8226', 'https://www.navos.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Outpatient mental health services for adults,youth,and children,including assessment,therapy}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('SOUND Behavioral Health', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Community behavioral health agency offering addiction treatment assessments and outpatient alcohol/drug treatment for youth and adults, individual/couple/family/group mental health counseling, and integrated treatment for co-occurring disorders. Multiple Seattle-area locations.', '1600 E Olive Street', 'Seattle', 'King', 'WA', '98122', '(206) 302-2300', 'https://www.sound.health', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Community behavioral health agency offering addiction treatment assessments and outpatient alcohol/drug treatment for youth and adults,individual/couple/family/group mental health counseling,and integrated treatment for co-occurring disorders,Multiple Seattle-area locations}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6764920/pexels-photo-6764920.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Therapeutic Health Services - Summit/Seneca Branch (Seattle)', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Nonprofit CARF-accredited outpatient provider offering medication-assisted treatment (methadone/Suboxone) for opioid use disorder and mental health counseling services for adults and youth.', '1116 Summit Avenue', 'Seattle', 'King', 'WA', '98101', '(206) 323-0930', 'https://ths-wa.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Nonprofit CARF-accredited outpatient provider offering medication-assisted treatment (methadone/Suboxone) for opioid use disorder and mental health counseling services for adults and youth}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6759205/pexels-photo-6759205.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Therapeutic Health Services - Snohomish/Everett Branch', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Outpatient medication-assisted treatment (methadone/Suboxone) for opioid use disorder, plus mental health counseling services, serving northern King and Snohomish Counties. Walk-in MAT services accepted.', '2810 Colby Avenue', 'Everett', 'Snohomish', 'WA', '98201', '(206) 323-0930', 'https://ths-wa.org/locations/snohomish-everett-branch', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Outpatient medication-assisted treatment (methadone/Suboxone) for opioid use disorder,plus mental health counseling services,serving northern King and Snohomish Counties,Walk-in MAT services accepted}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Asian Counseling and Referral Service (ACRS)', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Behavioral health and human services organization serving the Asian and Pacific Islander community. Services include mental health counseling, substance use disorder treatment, aging and long-term care, employment services, food bank, and citizenship assistance. TTY: (800) 833-6384.', '3639 Martin Luther King Jr. Way South', 'Seattle', 'King', 'WA', '98144', '(206) 695-7600', 'https://acrs.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Behavioral health and human services organization serving the Asian and Pacific Islander community,Services include mental health counseling,substance use disorder treatment,aging and long-term care,employment services}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Seattle Counseling Service', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Founded in 1969, the oldest mental health agency in the United States focused on the LGBTQ+ community. Licensed community mental health agency providing counseling, therapy, and general wellness services to LGBTQ+ individuals.', '2033 6th Avenue, Suite 400', 'Seattle', 'King', 'WA', '98121', '(206) 323-1768', 'https://seattlecounseling.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Founded in 1969,the oldest mental health agency in the United States focused on the LGBTQ+ community,Licensed community mental health agency providing counseling,therapy,and general wellness services to LGBTQ+ individuals}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6764920/pexels-photo-6764920.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Comprehensive Healthcare - Yakima Center', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Comprehensive behavioral health nonprofit serving Yakima, Kittitas, and Klickitat Counties. Offers outpatient mental health services for adults, seniors, children, and families; substance use disorder treatment including MAT; crisis services; veteran services; and housing support. Joint Commission Gold Seal accredited.', '402 South Fourth Avenue', 'Yakima', 'Yakima', 'WA', '98902', '(509) 575-4084', 'https://comphc.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Comprehensive behavioral health nonprofit serving Yakima,Kittitas,and Klickitat Counties,Offers outpatient mental health services for adults,seniors}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified') ON CONFLICT DO NOTHING;INSERT INTO resources (name, category_id, subcategory, description, address, city, county, state, zip_code, phone, website, hours, accepts_uninsured, sliding_scale, medicaid, medicare, private_insurance, walk_ins_welcome, appointments, telehealth, cost_free, cost_estimate_min, cost_estimate_max, languages, accessibility, services, specialties, audiences, rating, photo_url, source) VALUES
('Behavioral Health Resources (BHR)', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'South Puget Sound''s largest comprehensive provider of behavioral health and substance use disorder treatment services since 1956. Serves residents of Thurston, Mason, and Grays Harbor Counties through adult and children''s outpatient programs. Sliding-fee scale available.', '3857 Martin Way East', 'Olympia', 'Thurston', 'WA', '98506', '(360) 704-7170', 'https://www.bhr.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{South Puget Sound''s largest comprehensive provider of behavioral health and substance use disorder treatment services since 1956,Serves residents of Thurston,Mason,and Grays Harbor Counties through adult and children''s outpatient programs,Sliding-fee scale available}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Frontier Behavioral Health', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Community behavioral health agency serving Spokane and eastern Washington. Provides adult outpatient services, child and family services, crisis intervention and ITA evaluations, inpatient evaluation and treatment, the 988 crisis line, PACT, wraparound intensive services (WISe), DBT programs, forensic services, and housing support.', '107 South Division Street', 'Spokane', 'Spokane', 'WA', '99202', '(509) 838-4651', 'https://fbhwa.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Community behavioral health agency serving Spokane and eastern Washington,Provides adult outpatient services,child and family services,crisis intervention and ITA evaluations,inpatient evaluation and treatment}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Sea Mar Community Health Centers - Seattle Behavioral Health Clinic', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'State-licensed community mental health agency providing culturally competent behavioral health services including assessment, individual and group therapy, psychiatric medication evaluation and management, and case management for adults and children. Specializes in service to Latino and underserved communities; serves regardless of ability to pay.', '8801 14th Avenue South', 'Seattle', 'King', 'WA', '98108', '(206) 764-4700', 'https://www.seamar.org/king-bh-seattle.html', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{State-licensed community mental health agency providing culturally competent behavioral health services including assessment,individual and group therapy,psychiatric medication evaluation and management,and case management for adults and children,Specializes in service to Latino and underserved communities; serves regardless of ability to pay}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Sea Mar Community Health Centers - White Center Behavioral Health Clinic', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Outpatient behavioral health clinic offering mental health and medication-assisted treatment services in the White Center neighborhood of south Seattle. Part of the Sea Mar network of 90+ clinics across western Washington.', '9650 15th Avenue SW', 'Seattle', 'King', 'WA', '98106', '(206) 965-1055', 'https://www.seamar.org/king-bh-whitecenter.html', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Outpatient behavioral health clinic offering mental health and medication-assisted treatment services in the White Center neighborhood of south Seattle,Part of the Sea Mar network of 90+ clinics across western Washington}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6764920/pexels-photo-6764920.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Catholic Community Services of Western Washington - Seattle Office (Behavioral Health)', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Provides child and family mental health counseling services, housing support, family and youth services, services for seniors and people with disabilities, and behavioral health programs across multiple counties in Western Washington.', '100 23rd Avenue South', 'Seattle', 'King', 'WA', '98144', '(206) 328-5696', 'https://ccsww.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Provides child and family mental health counseling services,housing support,family and youth services,services for seniors and people with disabilities,and behavioral health programs across multiple counties in Western Washington}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6764920/pexels-photo-6764920.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Catholic Community Services of Western Washington - Family Behavioral Health (Tacoma)', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Licensed children''s mental health provider offering Wraparound services for children, youth, and families across King, Pierce, Kitsap, Skagit, Snohomish, Whatcom, and Grays Harbor Counties. CARF-accredited.', '1001 North J Street', 'Tacoma', 'Pierce', 'WA', '98403', '(253) 761-3856', 'https://ccsfamilybehavioralhealth.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Licensed children''s mental health provider offering Wraparound services for children,youth,and families across King,Pierce,Kitsap}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6759205/pexels-photo-6759205.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Compass Health - Everett Colby Office', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Adult outpatient services including individual, family, and group therapy as well as community support services. Compass Health is a leading behavioral health provider serving Snohomish, Skagit, Island, San Juan, and Whatcom Counties. Crisis line: 1-800-584-3578.', '2722 Colby Avenue', 'Everett', 'Snohomish', 'WA', '98201', '(425) 349-6804', 'https://www.compasshealth.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Adult outpatient services including individual,family,and group therapy as well as community support services,Compass Health is a leading behavioral health provider serving Snohomish,Skagit}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6759205/pexels-photo-6759205.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Compass Health - Snohomish Triage Center', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Short-stay crisis triage and stabilization facility providing a safe, recovery-oriented environment for individuals experiencing behavioral health crises. Offers crisis assessment, stabilization, and connection to ongoing treatment services. Admissions: (888) 693-7200.', '3322 Broadway', 'Everett', 'Snohomish', 'WA', '98201', '(425) 249-2530', 'https://www.compasshealth.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Short-stay crisis triage and stabilization facility providing a safe,recovery-oriented environment for individuals experiencing behavioral health crises,Offers crisis assessment,stabilization,and connection to ongoing treatment services}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/6678075/pexels-photo-6678075.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Volunteers of America Western Washington - Behavioral Health & Crisis Services', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Comprehensive human services nonprofit providing 24/7 behavioral health and crisis line services (including the 988 Suicide & Crisis Lifeline) for Snohomish, Skagit, San Juan, Island, and Whatcom Counties. Offers telephone crisis intervention, emotional support, suicide prevention, and specialized lines for veterans, Spanish speakers, and American Indians/Alaska Natives. North Sound Regional Crisis Line: (800) 584-3578.', '2802 Broadway', 'Everett', 'Snohomish', 'WA', '98201', '(425) 259-3191', 'https://www.voaww.org/behavioralhealth', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Comprehensive human services nonprofit providing 24/7 behavioral health and crisis line services (including the 988 Suicide & Crisis Lifeline) for Snohomish,Skagit,San Juan,Island,and Whatcom Counties}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
