('NAMI North Central Washington', (SELECT id FROM resource_categories WHERE slug='mental-health'), '', 'Independent NAMI affiliate serving North Central Washington. Offers NAMI Provider education programs, peer-led support groups, mental health education, and community presentations. Call or text for information.', '1212 Connection Street', 'Wenatchee', 'Chelan', 'WA', '98801', '(509) 663-8282', 'https://namincwa.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, true, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{Independent NAMI affiliate serving North Central Washington,Offers NAMI Provider education programs,peer-led support groups,mental health education,and community presentations}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Community Health Care - Puyallup Health Center (Dental)', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC providing comprehensive dental care (preventive, restorative, emergency, minor oral surgery) for all ages across five dental clinics in Pierce County. Accepts Apple Health (Medicaid); sliding-fee discounts for the uninsured. No one denied care due to inability to pay.', '201 West Main Street', 'Puyallup', 'Pierce', 'WA', '98371', '(253) 722-2151', 'https://www.commhealth.org', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC providing comprehensive dental care (preventive,restorative,emergency,minor oral surgery) for all ages across five dental clinics in Pierce County,Accepts Apple Health (Medicaid); sliding-fee discounts for the uninsured}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/3779705/pexels-photo-3779705.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
('Neighborcare Health - 45th Street Clinic (Dental)', (SELECT id FROM resource_categories WHERE slug='dental'), '', 'FQHC dental clinic in Wallingford offering general dentistry, emergency care, extractions, fillings, crowns, bridges, dentures, and root canals for adults and children. Accepts WA Apple Health (Medicaid), Medicare Advantage, and private insurance; sliding-scale fees for the uninsured.', '1629 North 45th Street', 'Seattle', 'King', 'WA', '98103', '(206) 548-2964', 'https://neighborcare.org/clinics/45th-street', '{"mon":"9:00-17:00","tue":"9:00-17:00","wed":"9:00-17:00","thu":"9:00-17:00","fri":"9:00-17:00","sat":"Closed","sun":"Closed"}'::jsonb, true, true, true, true, true, false, true, false, false, 0, 200, '{English,Spanish}', '{wheelchair,ADA parking}', '{FQHC dental clinic in Wallingford offering general dentistry,emergency care,extractions,fillings,crowns}', '{}', '{Adults,Families}', 4.5, 'https://images.pexels.com/photos/5212295/pexels-photo-5212295.jpeg?auto=compress&cs=tinysrgb&w=800', 'verified'),
